story-context.interfaces:
- name: NestInterceptor
  kind: interface (NestJS)
  signature: |
    interface NestInterceptor {
      intercept(context: ExecutionContext, next: CallHandler): Observable | Promise<Observable>;
    }
  path: @nestjs/common
  usage: LoggingInterceptor must implement this interface

- name: LoggerService
  kind: service (injectable)
  signature: |
    @Injectable()
    class LoggerService implements NestLoggerService {
      log(message: string, context?: any): void;
      error(message: string, trace?: string, context?: any): void;
      warn(message: string, context?: any): void;
      debug(message: string, context?: any): void;
      info(message: string, context?: any): void; // Alias for log()
    }
  path: src/common/logger/logger.service.ts
  usage: Inject and use for logging in LoggingInterceptor

- name: sanitizeContext
  kind: utility function
  signature: |
    function sanitizeContext(obj: any): any
  path: src/config/logger.config.ts
  usage: Reference pattern for request body sanitization (if needed). Recursively removes sensitive fields from objects.

- name: uuid.v4
  kind: function
  signature: |
    import { v4 as uuidv4 } from 'uuid';
    const requestId: string = uuidv4();
  path: uuid package
  usage: Generate UUID v4 for X-Request-ID when not present in request headers

- name: process.hrtime.bigint
  kind: native function
  signature: |
    const startTime: bigint = process.hrtime.bigint();
    const duration: number = Number(endTime - startTime) / 1_000_000; // Convert to ms
  path: Node.js native
  usage: High-precision timestamp for accurate duration calculation (sub-millisecond accuracy)
